// // This module implements a 4-bit DRAM cell with a write and read operation. The cell stores a 4-bit data when a write signal is deasserted. When the read signal is deasserted, it outputs the stored data.
module dram_cell (
    input wire clk,
    input wire reset,
    input wire write,
    input wire read,
    input wire [3:0] data_in,
    output reg [3:0] data_out
);
    reg [3:0] memory;

    always @(posedge clk or posedge reset) begin
        if (reset) begin
            memory <= 4'b0000;
        end else if (write) begin
            memory <= data_in;
        end else if (read) begin
            data_out <= memory;
        end
    end
endmodule
